      for (i <- 0 until 16) {
        val row = i / 4
        val col = i % 4
        val digit = xStr.charAt(i) - '0'
        grid(row, col) = digit
      }

      // 3. Traverse the path and record the sequence
      var sequence = scala.collection.mutable.ListBuffer[Int]()
      var row = 0
      var col = 0

      // Record the starting cell value
      sequence += grid(row, col)

      // Apply 6 directions
      for (i <- 0 until 6) {
        val direction = directions(i)

        if (direction == 'D') {
          row += 1
        } else if (direction == 'R') {
          col += 1
        }

        // Boundary check (should always pass given problem constraints)
        if (row < 0 || row >= 4 || col < 0 || col >= 4) {
          return false
        }

        // Record the value at the new cell
        sequence += grid(row, col)
      }

      // 4. Check if the sequence is non-decreasing
      for (i <- 0 until sequence.size - 1) {
        if (sequence(i) > sequence(i + 1)) {
          return false
        }
      }

      true
    }

