/**
 * @param {string} lStr - The lower bound as a string, as it can be large.
 * @param {string} rStr - The upper bound as a string, as it can be large.
 * @param {string} directions - The direction string.
 * @return {number} The count of "good" integers in [l, r].
 */
function solve(lStr, rStr, directions) {
    // Since l and r can be up to 9 * 10^15, we should use BigInt for iteration if necessary,
    // but since the constraints are relatively tight for a direct loop (up to 10^16 iterations),
    // we will stick to standard Number type for iteration if possible, or BigInt if we need to iterate over all numbers.
    // Given the complexity of the check, a direct loop is likely intended if the constraints allow.
    // Max value is 9 * 10^15, which fits within standard JavaScript safe integer (2^53 - 1, ~9 * 10^15).

    const l = BigInt(lStr);
    const r = BigInt(rStr);

    let goodCount = 0;

    /**
     * Checks if a number x is a "good" integer.
     * @param {bigint} x - The integer to check.
     * @param {string} directions - The direction string.
     * @returns {boolean} True if x is good, false otherwise.
     */
    function isGood(x, directions) {
        // 1. Format x into a 16-digit string with leading zeros
        let xStr = x.toString();
        xStr = xStr.padStart(16, '0');

        // 2. Fill the 4x4 grid
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        for (let i = 0; i < 16; i++) {
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = parseInt(xStr[i]);
        }

        // 3. Traverse the path and record the sequence
        const sequence = [];
        let row = 0;
        let col = 0;

        // Record the starting cell value
        sequence.push(grid[row][col]);

        // Apply 6 directions to get 6 moves, resulting in 7 recorded values (1 start + 6 moves)
        for (let i = 0; i < 6; i++) {
            const direction = directions[i];

            if (direction === 'D') {
                row += 1;
            } else if (direction === 'R') {
                col += 1;
            }

            // Boundary check (though based on problem description, the path should stay within 4x4 if the input guarantees are met)
            // We assume the path stays valid as per the problem logic described.
            if (row < 0 || row >= 4 || col < 0 || col >= 4) {
                // Should not happen given the constraints (3D, 3R)
                return false; 
            }

            // Record the value at the new cell
            sequence.push(grid[row][col]);
        }

        // 4. Check if the sequence is non-decreasing
        for (let i = 0; i < sequence.length - 1; i++) {
            if (sequence[i] > sequence[i+1]) {
                return false;
            }
        }

        return true;
    }

    // Iterate from l to r
    let current = l;
    while (current <= r) {
        if (isGood(current, directions)) {
            goodCount++;
        }
        current = current + 1n;
    }

    return goodCount;
}

